    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('YÜKLEME RAMPALARI & DESTEK AYAKLARI', '', '', '', '', '', '', 2, 30, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== AKSLAR & SÜSPANSİYON (84 kalem) ========
