    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('AKSLAR & SÜSPANSİYON', '', '', '', '', '', '', 2, 40, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== FREN SİSTEMİ (18 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'FREN SİSTEMİ' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('FREN SİSTEMİ', '', '', '', '', '', '', 2, 50, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== LASTİKLER & JANTLAR (48 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'LASTİKLER & JANTLAR' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('LASTİKLER & JANTLAR', '', '', '', '', '', '', 2, 60, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== AYDINLATMA (63 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'AYDINLATMA' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('AYDINLATMA', '', '', '', '', '', '', 2, 70, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== BOYA & YÜZEYİŞLEM (52 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'BOYA & YÜZEYİŞLEM' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('BOYA & YÜZEYİŞLEM', '', '', '', '', '', '', 2, 80, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== ÇELİK YAPI (6 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'ÇELİK YAPI' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('ÇELİK YAPI', '', '', '', '', '', '', 2, 90, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== OPSİYONLAR & AKSESUARLAR (129 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'OPSİYONLAR & AKSESUARLAR' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('OPSİYONLAR & AKSESUARLAR', '', '', '', '', '', '', 2, 100, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== TESLİMAT (47 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'TESLİMAT' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('TESLİMAT', '', '', '', '', '', '', 2, 110, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    RAISE NOTICE 'Liste tipi tum bolumler import tamam.';
END$$;
